<body>
    <div class="dream-system-container">
        <div class="dream-card">
            <div class="tab-header">
                <button class="tab-button active" onclick="switchTab('summary')">
                    <span class="tab-icon">💤</span>
                    <span>梦境摘要</span>
                </button>
                <button class="tab-button" onclick="switchTab('branch')">
                    <span class="tab-icon">✦</span>
                    <span>剧情分支</span>
                </button>
            </div>
            <div class="tab-content active" id="summary-tab">
                <div id="summary-content"></div>
            </div>
            <div class="tab-content" id="branch-tab">
                <div id="branch-content"></div>
            </div>
        </div>
