    <script>
        const branchText = `$1`;
        const summaryNumber = `$2`;
        const summaryTime = `$3`;
        const summaryScene = `$4`;
        const summaryPlot = `$5`;

        function switchTab(tabName) {
            const tabs = document.querySelectorAll('.tab-button');
            const contents = document.querySelectorAll('.tab-content');
            tabs.forEach(tab => tab.classList.remove('active'));
            contents.forEach(content => content.classList.remove('active'));
            if (tabName === 'summary') {
                tabs[0].classList.add('active');
                document.getElementById('summary-tab').classList.add('active');
            } else {
                tabs[1].classList.add('active');
                document.getElementById('branch-tab').classList.add('active');
            }
        }

        function renderSummary() {
            const container = document.getElementById('summary-content');
            if (!summaryNumber.trim() || !summaryTime.trim() || !summaryScene.trim() || !summaryPlot.trim()) {
                container.innerHTML = '<div class="empty-state">暂无梦境摘要</div>';
                return;
            }
            container.innerHTML = `
                <div class="summary-meta">
                    <div class="meta-item">
                        <svg class="meta-icon" viewBox="0 0 24 24">
                            <path d="M19.349,3.665H4.651A2.651,2.651,0,0,0,2.005,6.316V21.135a.865.865,0,0,0,1.3.748l8.7-5.523,8.7,5.523a.865.865,0,0,0,1.3-.748V6.316A2.651,2.651,0,0,0,19.349,3.665Zm-.865,15.722-7.975-5.064a.865.865,0,0,0-1.018,0L3.743,19.387V6.316a.9.9,0,0,1,.9-.9H19.349a.9.9,0,0,1,.9.9Z"/>
