                        <span class="meta-text">${summaryNumber.trim()}</span>
                    </div>
                    <div class="meta-item">
                        <svg class="meta-icon" viewBox="0 0 24 24">
                            <path d="M19,4h-1V2h-2v2H8V2H6v2H5C3.89,4,3.01,4.9,3.01,6L3,20c0,1.1,0.89,2,2,2h14c1.1,0,2-0.9,2-2V6C21,4.9,20.1,4,19,4z M19,20H5V10h14V20z"/>
                        </svg>
                        <span class="meta-text">${summaryTime.trim()}</span>
                    </div>
                    <div class="meta-item">
                        <svg class="meta-icon" viewBox="0 0 24 24">
                            <path d="M12,2C8.13,2,5,5.13,5,9c0,5.25,7,13,7,13s7-7.75,7-13C19,5.13,15.87,2,12,2z M12,11.5c-1.38,0-2.5-1.12-2.5-2.5s1.12-2.5,2.5-2.5s2.5,1.12,2.5,2.5S13.38,11.5,12,11.5z"/>
                        </svg>
                        <span class="meta-text">${summaryScene.trim()}</span>
                    </div>
                </div>
                <p class="summary-plot">${summaryPlot.trim()}</p>
            `;
        }

        function renderBranch() {
            const container = document.getElementById('branch-content');
            if (!branchText || !branchText.trim()) {
                container.innerHTML = '<div class="empty-state">暂无剧情分支</div>';
                return;
            }
            const options = branchText.trim().split('\n').filter(line => line.trim());
            if (options.length === 0) {
                container.innerHTML = '<div class="empty-state">暂无剧情分支</div>';
                return;
            }
            const optionsHTML = options.map((option, index) => `
                <div class="branch-option" onclick="selectBranch('${option.trim().replace(/'/g, "\\'")}')">
                    <span class="option-number">${index + 1}</span>
                    <span class="option-text">${option.trim()}</span>
                </div>
            `).join('');
            container.innerHTML = `<div class="branch-options">${optionsHTML}</div>`;
        }

        async function selectBranch(option) {
            await triggerSlashWithResult('/send ' + option);
            await new Promise(resolve => setTimeout(resolve, 100));
            triggerSlash('/trigger');
        }

        renderSummary();
        renderBranch();
    </script>
